// Server-side validation — mirrors hospital-form/index.html
const body = $input.first().json.body || $input.first().json;

const FACILITY_TYPES = [
  'General Hospital',
  'Multi-specialty Clinic',
  'Dental Clinic',
  'Pathology Lab',
  'Diagnostic Center',
  'Physiotherapy Clinic',
  'Eye Clinic',
  'ENT Clinic',
  'Other Medical Facility',
];

const hospital_name = String(body.hospital_name || '').trim();
const facility_type = String(body.facility_type || '').trim();
const address = String(body.address || '').trim();
const doctor_name = String(body.doctor_name || '').trim();
const doctor_expertise = String(body.doctor_expertise || '').trim();

const errors = [];

if (!hospital_name || hospital_name.length < 2)
  errors.push('hospital_name: required, minimum 2 characters');

if (!FACILITY_TYPES.includes(facility_type))
  errors.push('facility_type: required, must be a supported facility type');

if (!address || address.length < 5)
  errors.push('address: required, minimum 5 characters');

if (!doctor_name || doctor_name.length < 2)
  errors.push('doctor_name: required, minimum 2 characters');

if (!doctor_expertise || doctor_expertise.length < 2)
  errors.push('doctor_expertise: required, minimum 2 characters');

if (errors.length > 0) {
  return [{ json: { _valid: false, _errors: errors } }];
}

return [{
  json: {
    _valid: true,
    _errors: [],
    hospital_name,
    facility_type,
    address,
    doctor_name,
    doctor_expertise,
  }
}];
